  ('disabled-7c4986e7-moex-00156', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '在其他條件不變下，如果香蕉肥料價格大幅上漲，下列敘述何者正確？', '["香蕉需求增加", "香蕉需求減少", "香蕉供給增加", "香蕉供給減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00157', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '若某一消費者之效用函數為 U(X,Y) = Min{2X, Y}，其預算限制式為 2X+Y=100。根據以上假設，下列敘述何者正確？', '["此一消費者之效用極大最適消費組合為X財貨40單位，Y財貨20單位", "此一消費者之效用極大最適消費組合中，X財貨的消費量是Y財貨的2倍", "此一消費者之效用極大最適消費組合下，兩財貨之支出金額均為50", "對此消費者而言，兩財貨的邊際替代率固定 30660"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00158', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '在其他條件不變下，今年夏天天氣炎熱，西瓜需求大幅增加，西瓜園的：', '["勞動供給上升", "勞動供給下降", "勞動需求上升", "勞動需求下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00159', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '假設一家廠商的生產函數為Q=L0.4K0.6，L為勞動、K為資本，下列敘述 何者正確？', '["此廠商的生產過程呈現規模報酬遞增", "兩種生產要素在生產過程中無法互相替代", "在生產過程中兩種生產要素都將被使用", "在生產過程中當勞動僱用增加，呈現勞動邊際產量遞增"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00160', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '阿甘小吃店為一完全競爭廠商，短期所使用的固定生產要素為店面，變動 生產要素為勞動。給定其他條件不變下，下列敘述何者正確？', '["若店面租金上漲，阿甘小吃店的短期供給線上移；若工資上漲，阿甘小 吃店的短期供給線上移", "若店面租金上漲，阿甘小吃店的短期供給線不變；若工資上漲，阿甘小 吃店的短期供給線上移", "若店面租金上漲，阿甘小吃店的短期供給線上移；若工資上漲，阿甘小 吃店的短期供給線不變", "若店面租金上漲，阿甘小吃店的短期供給線不變；若工資上漲，阿甘小 吃店的短期供給線不變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00161', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '商品A的市場結構屬於完全競爭市場，市場需求函數為Q = 15P，市場供給 D 函數為：Q = P5。假設在此市場內有一廠商的成本函數為TC = 10+0.1q2， S 則在利潤最大化的行為準則下，此廠商的利潤水準為何？', '["230", "240", "250", "260"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00162', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '假設一個獨占性競爭廠商面對以下的需求曲線，此廠商的固定成本為$9， 且每單位產量的邊際成本為$3，此廠商利潤最大的產量為下列何者？ 價格（$） 30 27 24 21 18 15 12 9 6 3 數量 3 6 9 12 15 18 21 24 27 30', '["介於6單位至9單位", "介於9單位至12單位", "介於12單位至15單位", "介於15單位至18單位 30660"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00163', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '下列何種均衡屬於奈許均衡（Nashequilibrium）？', '["給定對手的策略下，所有玩家都選擇對自己的最佳反應策略時所達成 的均衡", "所有玩家都選擇對自己最有利的策略時所達成的均衡", "所有玩家都選擇造成最小損失的策略時所達成的均衡", "所有的玩家都選擇混合策略時所達成的均衡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00164', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '關於失業之敘述，下列何者錯誤？', '["有工作意願的人若找不到工作，代表勞動市場處於不均衡的狀態", "努力找尋工作但找不到工作的人，占勞動力的比例稱為失業率", "失業率越高代表一國勞動市場配置效率越差", "失業率降低對社會而言，必定是件好消息"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00165', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-112-d3ff7f6b', 'sub-disabled-7c4986e7-05', NULL, 'single_choice', '其他條件不變情形下，如果蘋果價格下跌，相對於蘋果跌價前的情況，蘋 果跌價後：', '["蘋果園工人的工資上漲", "蘋果園工人的工資不變", "蘋果園增加工人數量", "蘋果園裁減工人數量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:59+00:00", "source_pdf_sha1": "a5e0c545b665", "answer_pdf_sha1": "c46bc5edfb74", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "306", "s": "0903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
